}

// Step 2: Fetch narratives for ALL orgs for niche context
const orgNarratives = {};
for (const org of orgs) {
  try {
    const narratives = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/documents?org_id=eq.' + encodeURIComponent(org.id) + '&select=title,extracted_text,category&order=updated_at.desc&limit=10',
      headers,
    });
    if (Array.isArray(narratives) && narratives.length > 0) {
      const parts = narratives.map(n => {
        const label = n.title || n.category || '';
        const text = n.extracted_text || '';
        return label + ': ' + text;
      });
      orgNarratives[org.id] = parts.join('\n\n');
    } else {
      orgNarratives[org.id] = '';
    }
  } catch (e) {
    orgNarratives[org.id] = '';
  }
}

// Step 3: Collect all source_ids from incoming grants
const sourceIds = items
  .map(item => {
    const grant = item.json.grant || item.json;
    return (grant.oppNum || grant.source_id || '').trim();
  })
  .filter(id => id.length > 0);

// Step 4: Fetch existing org_id+source_id pairs from Supabase to avoid duplicates
const existingPairs = new Set();
for (let i = 0; i < sourceIds.length; i += 500) {
  const chunk = [...new Set(sourceIds.slice(i, i + 500))];
  const filter = chunk.map(id => `"${id}"`).join(',');
  try {
    const response = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/grants?source_id=in.(' + filter + ')&select=source_id,org_id',
      headers,
    });
    if (Array.isArray(response)) {
      response.forEach(r => existingPairs.add(r.org_id + '::' + r.source_id));
    }
  } catch (e) {
    // If check fails, continue - DB upsert will handle duplicates
  }
}

// Step 5: Build grants list from incoming items
const allGrants = [];
for (const item of items) {
  const grant = item.json.grant || item.json;
  allGrants.push({
    title: grant.title || '',
    agency: grant.agency || null,
    agencyCode: grant.agencyCode || '',
    description: grant.description || '',
    awardFloor: grant.awardFloor || 0,
    awardCeiling: grant.awardCeiling || 0,
    openDate: grant.openDate || '',
    closeDate: grant.closeDate || '',
    status: grant.status || '',
    source: grant.source || 'Grant Scanner',
    source_id: grant.oppNum || grant.source_id,
    source_url: grant.link || grant.source_url,
    id: grant.id,
    matchedKeywords: grant.matchedKeywords,
    relevanceScore: grant.relevanceScore,
  });
}

// Step 6: Output one item per org with all new grants for that org
const results = [];
for (const org of orgs) {
  const newGrants = allGrants.filter(g => {
    const sourceId = (g.source_id || '').trim();
    return !sourceId || !existingPairs.has(org.id + '::' + sourceId);
  });

  if (newGrants.length === 0) continue;

  results.push({
    json: {
      org,
      nicheSummary: orgNarratives[org.id] || '',
      grants: newGrants,
    }
  });
}

if (results.length === 0) {
  return [{ json: { noRelevantGrants: true, message: 'No new grant-org pairs to process' } }];
}

return results;

