const items = $input.all();
 const codeItems = $('Code in JavaScript5').all();
 const results = [];

 // There's one AI response item and one codeItems item per org
 items.forEach((item, index) => {
   const origData = codeItems[index]?.json || {};
   const org = origData.org || {};
   const grants = origData.grants || [];
   const aiText = item.json?.output?.[0]?.content?.[0]?.text || '';

   // Parse AI response — now an array of per-grant results
   let aiResults = [];
   try {
     const cleaned = aiText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
     aiResults = JSON.parse(cleaned);
     if (!Array.isArray(aiResults)) aiResults = [aiResults];
   } catch (e) {
     // If parse fails, pass all grants through with defaults
     aiResults = grants.map(g => ({
       source_id: g.source_id,
       grant_type: 'federal',
       grant_state: null,
       location_eligible: true,
       niche_aligned: true,
       eligible: true,
       reason: 'AI parse failed, defaulting to eligible'
     }));
   }

   // Build a lookup map: source_id -> AI result
   const aiMap = {};
   for (const r of aiResults) {
     if (r.source_id) aiMap[r.source_id] = r;
   }

   // Match each grant to its AI result
   for (const grant of grants) {
     const sourceId = grant.source_id || grant.oppNum || '';
     const ai = aiMap[sourceId] || { eligible: true, reason: 'No AI result found, defaulting to eligible', grant_type: 'unknown' };

     if (ai.eligible === false) continue;

     const description = grant.description || '';

     const descriptionHtml = '<div><h3>Grant Opportunity</h3>' +
       '<p><strong>Source:</strong> ' + (grant.source || '') + '</p>' +
       '<p><strong>Agency:</strong> ' + (grant.agency || '') + '</p>' +
       '<p><strong>Type:</strong> ' + (ai.grant_type || 'unknown') + '</p>' +
       (ai.grant_state ? '<p><strong>State:</strong> ' + ai.grant_state + '</p>' : '') +
       '<p><strong>Award Range:</strong> $' + (grant.awardFloor || 0) + ' - $' + (grant.awardCeiling || 0) + '</p>' +
       '<p><strong>Open Date:</strong> ' + (grant.openDate || '') + '</p>' +
       '<p><strong>Deadline:</strong> ' + (grant.closeDate || '') + '</p>' +
       '<hr><h4>Description:</h4>' +
       '<p>' + description + '</p>' +
       '<p><em>Location Filter: ' + (ai.reason || 'N/A') + '</em></p>' +
       '<hr>' +
       '<p><a href="' + (grant.source_url || grant.link || '') + '">View Original Listing</a></p>' +
       '</div>';

     let deadlineValue = null;
     if (grant.closeDate && grant.closeDate !== 'See listing' && grant.closeDate !== 'Not specified' && grant.closeDate !== 'Rolling') {
       const d = new Date(grant.closeDate);
       if (!isNaN(d.getTime())) {
         const yyyy = d.getUTCFullYear();
         const mm = String(d.getUTCMonth() + 1).padStart(2, '0');
         const dd = String(d.getUTCDate()).padStart(2, '0');
         deadlineValue = yyyy + '-' + mm + '-' + dd + 'T00:00:00.000Z';
       } else {
         deadlineValue = grant.closeDate;
       }
     }

     results.push({
       json: {
         org_id: org.id,
         title: grant.title || '',
         funder_name: grant.agency || null,
         description: description,
         amount: grant.awardCeiling > 0 ? grant.awardCeiling : null,
         deadline: deadlineValue,
         stage: 'discovery',
         source: grant.source || 'Grant Scanner',
         source_id: sourceId,
         source_url: grant.source_url || grant.link,
         metadata: {
           grants_gov_id: grant.id,
           agency_code: grant.agencyCode,
           open_date: grant.openDate,
           award_floor: grant.awardFloor,
           award_ceiling: grant.awardCeiling,
           grant_type: ai.grant_type || 'unknown',
           grant_state: ai.grant_state || null,
           location_filter_reason: ai.reason || '',
           location_eligible: ai.location_eligible !== false,
           niche_aligned: ai.niche_aligned !== false,
           priority: 'medium',
           description_html: descriptionHtml
         }
       }
     });
   }
 });

 if (results.length === 0) {
   return [{ json: { noRelevantGrants: true, message: 'No eligible grants after location and niche filtering' } }];
 }

 return results;
